class SyntaxError {
  name: string;
  expected: any[];
  found: string | null;
  message: string;
  offset: number;
  line: number;
  column: number;
  constructor(
    expected: any[],
    found: string | null,
    offset: number,
    line: number,
    column: number
  ) {
    this.name = "SyntaxError";
    this.expected = expected;
    this.found = found;
    this.message = SyntaxError.buildMessage(expected, found);
    this.offset = offset;
    this.line = line;
    this.column = column;
  }

  static buildMessage(expected: Array<string | null>, found: string | null) {
    let expectedHumanized;

    switch (expected.length) {
      case 0:
        expectedHumanized = "end of input";
        break;
      case 1:
        expectedHumanized = expected[0];
        break;
      default:
        expectedHumanized =
          expected.slice(0, expected.length - 1).join(", ") +
          " or " +
          expected[expected.length - 1];
    }

    const foundHumanized = found ? quote(found) : "end of input";

    return (
      "Expected " + expectedHumanized + " but " + foundHumanized + " found."
    );
  }
}
